 Here is the code for a Discord bot using Discord.js v14 with one slash command ban:

```js
const Discord = require('discord.js')
const client = new Discord.Client()

const prefix = '!'

client.on('ready', () => {
  console.log('Bot is ready!')
})

client.on('message', msg => {
  if (msg.content.startsWith(prefix) && msg.author.bot) return

  const args = msg.content.slice(prefix.length).trim().split(/ +/)
  const command = args.shift().toLowerCase()

  if (command === 'ban') {
    if (!msg.member.hasPermission('BAN_MEMBERS')) return

    const target = msg.mentions.members.first()
    if (!target) return msg.reply('Please mention the member to ban.')

    msg.reply(`Banning: ${target.user.tag}`)
    target.bannable.ban().then(() => msg.reply(`Banned: ${target.user.tag}`))
  }
})

client.login('BOT TOKEN')
```

This uses Discord.js v14 to create a Discord bot. It listens for the 'ready' event and logs a message that the bot is ready. It also listens for messages and parses them for slash commands starting with the prefix '!'. For the ban command, it checks if the message author has the 'BAN_MEMBERS' permission and then bans the first mentioned member if they are mentioned. It replies to the message with the ban message.

